from wordworld.ui.console import main


if __name__ == "__main__":
    main()

import re
import unicodedata
from typing import Optional

from wordworld.core.engine import GameEngine
from wordworld.config.paths import SAVE_PATH


_CHINESE_NUMBER_MAP = {
    "零": 0,
    "〇": 0,
    "一": 1,
    "二": 2,
    "两": 2,
    "三": 3,
    "四": 4,
    "五": 5,
    "六": 6,
    "七": 7,
    "八": 8,
    "九": 9,
}

_MAIN_COMMAND_ALIASES = {
    "探索": "1",
    "探索区域": "1",
    "移动": "2",
    "移动区域": "2",
    "区域移动": "2",
    "修炼": "3",
    "切磋": "4",
    "推进": "5",
    "推进主线": "5",
    "主线": "5",
    "关键目标": "5",
    "休息": "6",
    "状态": "7",
    "查看状态": "7",
    "行囊": "8",
    "背包": "8",
    "物品": "8",
    "保存": "9",
    "存档": "9",
    "退出": "q",
    "离开": "q",
}


def normalize_input(raw: str) -> str:
    """Normalize console input from different input methods and terminals."""

    return unicodedata.normalize("NFKC", raw).strip().lower()


def parse_menu_number(raw: str) -> Optional[int]:
    text = normalize_input(raw)
    if not text:
        return -1
    if text in {"q", "b"}:
        return None
    if text in _CHINESE_NUMBER_MAP:
        return _CHINESE_NUMBER_MAP[text]
    match = re.match(r"^(\d+)", text)
    if match:
        return int(match.group(1))
    return -1


def parse_main_command(raw: str) -> str:
    text = normalize_input(raw)
    if text in {"q", "b"}:
        return "q"
    number = parse_menu_number(text)
    if number is None:
        return "q"
    if number != -1:
        return str(number)
    compact_text = re.sub(r"[\s.。:：、-]+", "", text)
    return _MAIN_COMMAND_ALIASES.get(compact_text, text)

def line() -> None:
    print("=" * 72)


def ask_number(prompt: str = "> ") -> Optional[int]:
    number = parse_menu_number(input(prompt))
    if number == -1:
        print("请输入有效数字，或输入 b 返回。")
    return number


def show_result(game: GameEngine) -> None:
    if game.last_message:
        print(f"\n【行动结果】{game.last_message}")


def combat_loop(game: GameEngine) -> None:
    while game.combat is not None:
        line()
        print("【回合战斗】")
        print(game.combat_text())
        print("\n1. 普通攻击  2. 施展斗技  3. 防御  4. 使用丹药  5. 逃跑  6. 本场自动战斗")
        choice = ask_number()
        if choice is None:
            choice = 5
        if choice == 1:
            game.combat_action("attack")
        elif choice == 2:
            skills = game.combat_skills()
            if not skills:
                print("尚未掌握可用斗技。")
                continue
            print("\n选择斗技：")
            for index, skill in enumerate(skills, start=1):
                print(f"{index}. {skill['name']}（{skill['rank']}）- {skill['description']}")
            skill_choice = ask_number()
            if skill_choice is None or not 1 <= skill_choice <= len(skills):
                continue
            game.combat_action("skill", skills[skill_choice - 1]["id"])
        elif choice == 3:
            game.combat_action("defend")
        elif choice == 4:
            game.combat_action("item")
        elif choice == 5:
            game.combat_action("escape")
        elif choice == 6:
            game.auto_battle()
        else:
            print("没有这个战斗行动。")
            continue
        show_result(game)


def encounter_loop(game: GameEngine) -> None:
    encounter = game.active_encounter
    if encounter is None:
        show_result(game)
        return
    line()
    print("【探索奇遇】")
    print(encounter["text"])
    options = game.encounter_options()
    for index, option in options:
        print(f"{index}. {option['text']}")
    choice = ask_number()
    if choice is None:
        game.active_encounter = None
        game.last_message = "你谨慎地离开了现场。"
        return
    game.choose_encounter_option(choice)
    show_result(game)
    if game.combat is not None:
        combat_loop(game)


def travel_menu(game: GameEngine) -> None:
    maps = game.available_maps()
    line()
    print("【区域移动】")
    for index, map_rule in enumerate(maps, start=1):
        current = "（当前）" if map_rule["id"] == game.current_map()["id"] else ""
        danger = "安全区域" if map_rule["safe_zone"] else "危险区域"
        print(
            f"{index}. {map_rule['name']}{current}｜剧情已开放｜推荐等级 {map_rule['recommend_level']}"
            f"｜{danger}｜{map_rule['description']}"
        )
    choice = ask_number()
    if choice is not None and 1 <= choice <= len(maps):
        game.travel(maps[choice - 1]["id"])


def inventory_menu(game: GameEngine) -> None:
    while True:
        line()
        print("【行囊】")
        items = game.player.get("items", [])
        if not items:
            print("行囊空空。")
            return
        for index, item_id in enumerate(items, start=1):
            rule = game.item_rules.get(item_id, {})
            print(f"{index}. {game.item_name(item_id)}｜{rule.get('description', '')}")
        print("输入编号使用道具，输入 b 返回。")
        choice = ask_number()
        if choice is None:
            return
        if 1 <= choice <= len(items):
            game.use_item(items[choice - 1])
            show_result(game)


def story_mission(game: GameEngine) -> None:
    phase = game.current_story_phase()
    if phase is None:
        print("主要目标已经全部完成。")
        return
    requirement = game.story_requirement()
    line()
    print(f"【关键目标】{phase['title']}")
    print(f"推进需求：冒险阅历 {requirement}｜当前 {game.player['adventure_points']}")
    print(f"\n背景：{phase['background']}")
    print(f"目标：{phase['objective']}")
    print(f"风险：{phase['risk']}")
    print("\n阶段子节点：")
    current = game.current_story_subnode()
    for index, subnode in enumerate(phase["subnodes"], start=1):
        if index <= game.player["story_substage"]:
            marker = "已完成"
        elif subnode is current:
            marker = "当前"
        else:
            marker = "未开始"
        print(
            f"  {index}. [{marker}] {subnode['title']}：{subnode['objective']}"
            f"（条件：{subnode['condition']}）"
        )
    if current:
        print(f"\n当前行动：完成子节点“{current['title']}”")
    else:
        print(f"\n阶段结算条件：{phase['condition']}")
    print("\n1. 尝试推进当前节点  2. 暂时离开")
    choice = ask_number()
    if choice == 1:
        game.advance_story()
        show_result(game)


def resolve_required_schedule(game: GameEngine) -> None:
    node = game.pending_schedule_node()
    if node is None:
        return
    line()
    print("【强制日程节点】")
    print(game.schedule_text(node))
    input("\n时间已到，按回车参加并结算。")
    game.resolve_schedule_node()
    show_result(game)


def show_hub(game: GameEngine) -> None:
    map_rule = game.current_map()
    line()
    phase = "夜间" if game.is_night() else "白天"
    print(f"【{game.time_text()}｜{phase}｜{map_rule['name']}】{map_rule['description']}")
    print(
        f"{game.player['name']}｜{game.realm_name()} Lv.{game.player['level']}｜"
        f"生命 {game.player['hp']}/{game.player['max_hp']}｜"
        f"斗气 {game.player['douqi']}｜体力 {game.player['stamina']}｜"
        f"冒险阅历 {game.player['adventure_points']}"
    )
    phase = game.current_story_phase()
    print(f"当前目标：{phase['title'] if phase else '所有关键目标已完成'}")
    subnode = game.current_story_subnode()
    if subnode:
        print(f"当前子节点：{subnode['title']}｜{subnode['objective']}")
    node = game.next_schedule_node()
    if node:
        goals = game.schedule_text(node).splitlines()[-1]
        print(
            f"临近日程：{game.schedule_text(node).splitlines()[0]}"
            f"｜{game.schedule_countdown_text(node)}｜{goals}"
        )
    print("\n1. 探索区域  2. 移动区域  3. 修炼  4. 切磋")
    print("5. 推进主线  6. 休息  7. 查看状态  8. 行囊  9. 保存  q. 退出")


def main() -> None:
    game = GameEngine()
    print("斗破苍穹：沉浸式回合制 RPG")
    if SAVE_PATH.exists() and input("检测到存档，是否读取？ y/n：").strip().lower() == "y":
        game.load()
    else:
        name = input("请输入主角姓名，直接回车则为萧炎：").strip()
        game.new_game(name or None)

    while True:
        if game.pending_schedule_node() is not None:
            resolve_required_schedule(game)
            continue
        show_hub(game)
        command = parse_main_command(input("\n> "))
        if command == "q":
            print("旅途暂告一段落。")
            break
        if command == "1":
            game.explore()
            encounter_loop(game)
        elif command == "2":
            travel_menu(game)
            show_result(game)
        elif command == "3":
            game.cultivate()
            show_result(game)
        elif command == "4":
            game.begin_training_combat()
            combat_loop(game)
        elif command == "5":
            story_mission(game)
        elif command == "6":
            game.rest()
            show_result(game)
        elif command == "7":
            line()
            print(game.status_text())
        elif command == "8":
            inventory_menu(game)
        elif command == "9":
            game.save()
            print("进度已保存。")
        else:
            print("请输入菜单中的行动编号。")


if __name__ == "__main__":
    main()

import re
import xml.etree.ElementTree as ET
from functools import lru_cache
from pathlib import Path
from typing import Any, Dict, Iterable, List
from zipfile import ZipFile


from wordworld.config.paths import WORKBOOK_PATH

SPREADSHEET_NS = "http://schemas.openxmlformats.org/spreadsheetml/2006/main"
DOCUMENT_REL_NS = "http://schemas.openxmlformats.org/officeDocument/2006/relationships"
PACKAGE_REL_NS = "http://schemas.openxmlformats.org/package/2006/relationships"

ROW_TAG = f"{{{SPREADSHEET_NS}}}row"
CELL_TAG = f"{{{SPREADSHEET_NS}}}c"
VALUE_TAG = f"{{{SPREADSHEET_NS}}}v"
TEXT_TAG = f"{{{SPREADSHEET_NS}}}t"
COLUMN_PATTERN = re.compile(r"^[A-Z]+")


def _to_int(value: Any, default: int = 0) -> int:
    if value in (None, ""):
        return default
    return int(float(value))


def _to_bool(value: Any) -> bool:
    return str(value).strip().lower() in {"1", "yes", "true", "y"}


def _cell_value(cell: ET.Element) -> str:
    if cell.get("t") == "inlineStr":
        return "".join(node.text or "" for node in cell.iter(TEXT_TAG))
    value = cell.find(VALUE_TAG)
    return value.text if value is not None and value.text is not None else ""


class WorkbookReader:
    def __init__(self, path: Path) -> None:
        self.path = path

    def _sheet_paths(self, archive: ZipFile) -> Dict[str, str]:
        workbook = ET.fromstring(archive.read("xl/workbook.xml"))
        relationships = ET.fromstring(archive.read("xl/_rels/workbook.xml.rels"))
        targets = {
            relation.get("Id"): relation.get("Target", "")
            for relation in relationships.findall(f"{{{PACKAGE_REL_NS}}}Relationship")
        }

        result: Dict[str, str] = {}
        sheets = workbook.find(f"{{{SPREADSHEET_NS}}}sheets")
        if sheets is None:
            return result

        for sheet in sheets:
            relation_id = sheet.get(f"{{{DOCUMENT_REL_NS}}}id", "")
            target = targets.get(relation_id, "").replace("\\", "/")
            if target.startswith("/"):
                target = target.lstrip("/")
            elif not target.startswith("xl/"):
                target = f"xl/{target}"
            result[sheet.get("name", "")] = target
        return result

    def read_sheets(self, sheet_names: Iterable[str]) -> Dict[str, List[Dict[str, str]]]:
        requested = set(sheet_names)
        result: Dict[str, List[Dict[str, str]]] = {}
        with ZipFile(self.path) as archive:
            paths = self._sheet_paths(archive)
            missing = requested.difference(paths)
            if missing:
                raise ValueError(f"工作簿缺少配置表：{', '.join(sorted(missing))}")
            for sheet_name in requested:
                result[sheet_name] = self._read_sheet(archive, paths[sheet_name])
        return result

    @staticmethod
    def _read_sheet(archive: ZipFile, path: str) -> List[Dict[str, str]]:
        headers: Dict[str, str] = {}
        rows: List[Dict[str, str]] = []
        with archive.open(path) as stream:
            for _, element in ET.iterparse(stream, events=("end",)):
                if element.tag != ROW_TAG:
                    continue

                values: Dict[str, str] = {}
                for cell in element.findall(CELL_TAG):
                    match = COLUMN_PATTERN.match(cell.get("r", ""))
                    if match:
                        values[match.group(0)] = _cell_value(cell)

                if not headers:
                    headers = values
                else:
                    rows.append(
                        {
                            header: values.get(column, "")
                            for column, header in headers.items()
                            if header
                        }
                    )
                element.clear()
        return rows


def _parse_events(rows: List[Dict[str, str]]) -> List[Dict[str, Any]]:
    events: List[Dict[str, Any]] = []
    for row in rows:
        event_id = row.get("ID", "")
        if not event_id:
            continue
        options: List[Dict[str, Any]] = []
        for index in range(1, 5):
            text = row.get(f"Opt{index}_Text", "")
            if not text:
                continue
            options.append(
                {
                    "text": text,
                    "conditions": row.get(f"Opt{index}_Condition", ""),
                    "next": row.get(f"Opt{index}_Next", ""),
                    "effects": row.get(f"Opt{index}_Effect", ""),
                }
            )
        events.append(
            {
                "id": event_id,
                "title": row.get("Notes", "") or event_id,
                "kind": row.get("Type", "story") or "story",
                "pool": row.get("Pool", ""),
                "text": row.get("Text", ""),
                "conditions": row.get("Pre_Condition", ""),
                "weight": _to_int(row.get("Weight"), 1),
                "options": options,
                "speaker_id": row.get("Speaker_ID", ""),
                "scene_npcs": [
                    item for item in row.get("Scene_NPCs", "").split(",") if item
                ],
                "faction_context": [
                    item for item in row.get("Faction_Context", "").split(",") if item
                ],
            }
        )
    return events


def _parse_attributes(rows: List[Dict[str, str]]) -> Dict[str, Dict[str, Any]]:
    return {
        row["Attr_ID"]: {
            "id": row["Attr_ID"],
            "name": row.get("Name", row["Attr_ID"]),
            "initial": _to_int(row.get("Initial")),
            "min": _to_int(row.get("Min"), -999999999),
            "max": _to_int(row.get("Max"), 999999999),
        }
        for row in rows
        if row.get("Attr_ID")
    }


def _parse_relationships(rows: List[Dict[str, str]]) -> List[Dict[str, Any]]:
    relationships: List[Dict[str, Any]] = []
    for row in rows:
        relation_id = row.get("Relation_ID", "")
        if not relation_id:
            continue
        relationships.append(
            {
                "id": relation_id,
                "source": row.get("Source_ID", ""),
                "target": row.get("Target_ID", ""),
                "type": row.get("Relation_Type", ""),
                "initial_value": _to_int(row.get("Initial_Value")),
                "min_value": _to_int(row.get("Min_Value"), -100),
                "max_value": _to_int(row.get("Max_Value"), 100),
                "stage_rule": row.get("Stage_Rule", ""),
                "bidirectional": _to_bool(row.get("Is_Bidirectional")),
                "visible": _to_bool(row.get("Visible_To_Player")),
                "pre_condition": row.get("Pre_Condition", ""),
                "on_reach_effect": row.get("On_Reach_Effect", ""),
            }
        )
    return relationships


def _parse_level_progression(rows: List[Dict[str, str]]) -> List[Dict[str, Any]]:
    progression: List[Dict[str, Any]] = []
    for row in rows:
        raw_range = row.get("Level_Range", "")
        if not raw_range:
            continue
        if "-" in raw_range:
            start, end = raw_range.split("-", 1)
        else:
            start = end = raw_range
        progression.append(
            {
                "min_level": _to_int(start),
                "max_level": _to_int(end),
                "exp_formula": row.get("Exp_Formula", ""),
                "gains": {
                    "douqi": _to_int(row.get("Douqi_Gain")),
                    "hp": _to_int(row.get("HP_Gain")),
                    "atk": _to_int(row.get("ATK_Gain")),
                    "def": _to_int(row.get("DEF_Gain")),
                    "spd": _to_int(row.get("SPD_Gain")),
                },
            }
        )
    return progression


def _parse_options(row: Dict[str, str], count: int = 3) -> List[Dict[str, str]]:
    return [
        {
            "text": row.get(f"Opt{index}_Text", ""),
            "conditions": row.get(f"Opt{index}_Condition", ""),
            "next": row.get(f"Opt{index}_Next", ""),
            "effects": row.get(f"Opt{index}_Effect", ""),
        }
        for index in range(1, count + 1)
        if row.get(f"Opt{index}_Text")
    ]


def _parse_maps(rows: List[Dict[str, str]]) -> Dict[str, Dict[str, Any]]:
    return {
        row["Map_ID"]: {
            "id": row["Map_ID"],
            "name": row.get("Name", row["Map_ID"]),
            "region": row.get("Region", ""),
            "unlock_condition": row.get("Unlock_Condition", ""),
            "recommend_level": _to_int(row.get("Recommend_Level"), 1),
            "stamina_cost": _to_int(row.get("Explore_Stamina_Cost"), 5),
            "safe_zone": _to_bool(row.get("Safe_Zone")),
            "exit_event": row.get("Exit_Event", ""),
            "description": row.get("Description", ""),
        }
        for row in rows
        if row.get("Map_ID")
    }


def _parse_encounters(rows: List[Dict[str, str]]) -> List[Dict[str, Any]]:
    return [
        {
            "id": row["Event_ID"],
            "map_id": row.get("Map_ID", ""),
            "weight": _to_int(row.get("Weight"), 1),
            "text": row.get("Text", ""),
            "conditions": row.get("Pre_Condition", ""),
            "options": _parse_options(row),
        }
        for row in rows
        if row.get("Event_ID")
    ]


def _parse_enemies(rows: List[Dict[str, str]]) -> Dict[str, Dict[str, Any]]:
    return {
        row["Enemy_ID"]: {
            "id": row["Enemy_ID"],
            "name": row.get("Name", row["Enemy_ID"]),
            "type": row.get("Type", ""),
            "level": _to_int(row.get("Level"), 1),
            "hp": _to_int(row.get("HP"), 30),
            "atk": _to_int(row.get("ATK"), 5),
            "def": _to_int(row.get("DEF"), 2),
            "spd": _to_int(row.get("SPD"), 5),
            "drop_table": row.get("Drop_Table", ""),
            "exp_reward": _to_int(row.get("Exp_Reward"), 10),
            "win_next": row.get("Win_Next", ""),
            "lose_next": row.get("Lose_Next", ""),
            "notes": row.get("Notes", ""),
            "can_kill": "non_lethal" not in str(row.get("Notes", "")),
            "skills": [
                skill.strip() for skill in row.get("Skills", "").split(",") if skill.strip()
            ],
        }
        for row in rows
        if row.get("Enemy_ID")
    }


def _parse_items(rows: List[Dict[str, str]]) -> Dict[str, Dict[str, Any]]:
    return {
        row["Item_ID"]: {
            "id": row["Item_ID"],
            "name": row.get("Name", row["Item_ID"]),
            "type": row.get("Type", ""),
            "use_condition": row.get("Use_Condition", ""),
            "use_effect": row.get("Use_Effect", ""),
            "description": row.get("Description", ""),
        }
        for row in rows
        if row.get("Item_ID")
    }


def _parse_skills(rows: List[Dict[str, str]]) -> Dict[str, Dict[str, Any]]:
    return {
        row["Skill_ID"]: {
            "id": row["Skill_ID"],
            "name": row.get("Name", row["Skill_ID"]),
            "type": row.get("Type", ""),
            "rank": row.get("Rank", ""),
            "effect": row.get("Effect", ""),
            "description": row.get("Description", ""),
        }
        for row in rows
        if row.get("Skill_ID")
    }


def _parse_realms(rows: List[Dict[str, str]]) -> List[Dict[str, Any]]:
    return [
        {
            "id": row["Realm_ID"],
            "name": row.get("Name", row["Realm_ID"]),
            "min_level": _to_int(row.get("Min_Level"), 1),
            "max_level": _to_int(row.get("Max_Level"), 99),
        }
        for row in rows
        if row.get("Realm_ID")
    ]


@lru_cache(maxsize=4)
def _load_game_data_cached(path_text: str) -> Dict[str, Any]:
    path = Path(path_text)
    if not path.exists():
        raise FileNotFoundError(f"找不到最新剧情数据：{path}")

    sheets = WorkbookReader(path).read_sheets(
        {
            "Events_剧情配置",
            "Attributes_属性库",
            "Flags_开关库",
            "NPCs_人物表",
            "Relationships_关系表",
            "Level_Progression_等级成长",
            "Maps_地图库",
            "Map_Encounters_奇遇池",
            "Enemies_敌人配置",
            "Items_道具库",
            "Skills_斗技功法",
            "Realms_境界成长",
        }
    )
    events = _parse_events(sheets["Events_剧情配置"])
    if not events:
        raise ValueError("最新剧情数据中没有可用事件。")

    return {
        "events": events,
        "attributes": _parse_attributes(sheets["Attributes_属性库"]),
        "flag_defaults": {
            row["Flag_ID"]: _to_int(row.get("Default_Value"))
            for row in sheets["Flags_开关库"]
            if row.get("Flag_ID")
        },
        "npc_names": {
            row["Character_ID"]: row.get("Name", row["Character_ID"])
            for row in sheets["NPCs_人物表"]
            if row.get("Character_ID")
        },
        "relationships": _parse_relationships(sheets["Relationships_关系表"]),
        "level_progression": _parse_level_progression(
            sheets["Level_Progression_等级成长"]
        ),
        "maps": _parse_maps(sheets["Maps_地图库"]),
        "encounters": _parse_encounters(sheets["Map_Encounters_奇遇池"]),
        "enemies": _parse_enemies(sheets["Enemies_敌人配置"]),
        "items": _parse_items(sheets["Items_道具库"]),
        "skills": _parse_skills(sheets["Skills_斗技功法"]),
        "realms": _parse_realms(sheets["Realms_境界成长"]),
        "start_event": events[0]["id"],
        "source_path": str(path),
    }


def load_game_data(path: Path = WORKBOOK_PATH) -> Dict[str, Any]:
    return _load_game_data_cached(str(path.resolve()))

    # 通行描述与原文一致
    if transit_map_id:
        self.last_message = (
            f"你通过{TRANSIT_HUB_NAMES.get(transit_map_id, '中转站')}"
            f"抵达了{map_rule['name']}。{map_rule['description']}"
        )
    else:
        self.last_message = f"你抵达了{map_rule['name']}。{map_rule['description']}"
    return True

def rest(self) -> None:
    if not self._can_take_free_action():
        return
    self.player["hp"] = self.player["max_hp"]
    self.player["stamina"] = self.attribute_rules["stamina"]["initial"]
    periods = len(TIME_PERIODS) - int(self.player["time_period"])
    self.advance_time(periods)
    self.last_message = f"你休整到{self.time_text()}，生命与体力已经恢复。"

def cultivate(self) -> bool:
    if not self._can_take_free_action():
        return False
    if self.player["stamina"] < 10:
        self.last_message = "体力不足，先休息再修炼。"
        return False
    self.player["stamina"] -= 10
    soul_gain = 2 if self.is_night() else 1
    self.player["adventure_points"] += 1
    if "ring_awakened" not in self.player["flags"]:
        logs = self.apply_effects(f"soul:+{soul_gain}")
        action_text = "药老尚未苏醒，你只能感知戒指异动、锤炼灵魂。"
    else:
        logs = self.apply_effects(f"exp:+10,douqi:+2,soul:+{soul_gain}")
        action_text = "你依照药老指导运转斗气，完成了一轮修炼。"
    self.advance_time()
    self.last_message = action_text + "；获得冒险阅历 +1"
    if logs:
        self.last_message += "；" + "；".join(logs)
    return True

def explore(self) -> Optional[Dict[str, Any]]:
    if not self._can_take_free_action():
        return None
    map_rule = self.current_map()
    night_cost = 2 if self.is_night() else 0
    cost = map_rule["stamina_cost"] + night_cost
    if self.player["stamina"] < cost:
        self.last_message = "体力不足，无法继续探索。"
        return None
    self.player["stamina"] -= cost
    candidates = [
        encounter
        for encounter in self.encounters
        if encounter["map_id"] == map_rule["id"]
        and self.check_conditions(encounter.get("conditions"))
    ]
    if not candidates:
        self.player["adventure_points"] += 1
        self.advance_time()
        self.last_message = f"你探索了{map_rule['name']}，但没有特别发现。"
        return None
    self.active_encounter = random.choices(
        candidates,
        weights=[max(1, encounter["weight"]) for encounter in candidates],
        k=1,
    )[0]
    self.last_message = self.active_encounter["text"]
    return self.active_encounter

def encounter_options(self) -> List[Tuple[int, Dict[str, Any]]]:
    if self.active_encounter is None:
        return []
    return [
        (index, option)
        for index, option in enumerate(self.active_encounter["options"], start=1)
        if self.check_conditions(option.get("conditions"))
    ]

def choose_encounter_option(self, option_number: int) -> bool:
    option_map = {index: option for index, option in self.encounter_options()}
    if option_number not in option_map:
        self.last_message = "当前无法选择该行动。"
        return False
    option = option_map[option_number]
    logs = self.apply_effects(option.get("effects"))
    next_id = option.get("next", "")
    encounter_text = self.active_encounter["text"] if self.active_encounter else ""
    self.active_encounter = None
    self.player["adventure_points"] += 1
    if self.is_night():
        self.player["adventure_points"] += 1
        logs.append("夜间探索额外获得 1 点冒险阅历")
    if next_id.startswith("combat:"):
        self.combat_time_cost = 1
        self.begin_combat(next_id[7:])
        if logs:
            self.last_message = "；".join(logs) + "；" + self.last_message
    else:
        self.advance_time()
        self.last_message = "；".join(logs) if logs else f"你处理了这次遭遇：{encounter_text}"
    return True

def begin_training_combat(self) -> bool:
    if not self._can_take_free_action():
        return False
    level = int(self.player["level"])
    self.combat_time_cost = 1
    self.combat_is_training = True
    self.combat = {
        "enemy_id": "training_opponent",
        "name": "萧家陪练弟子",
        "level": level,
        "hp": 30 + level * 8,
        "max_hp": 30 + level * 8,
        "atk": 5 + level * 2,
        "def": 2 + level,
        "spd": 5 + level,
        "exp_reward": 10 + level * 4,
        "drop_table": "",
        "round": 1,
        "defending": False,
        "can_escape": True,
    }
    self.last_message = "陪练弟子摆开架势，回合战斗开始。"
    return True

def begin_combat(self, enemy_id: str) -> bool:
    enemy = self.enemies.get(enemy_id)
    if enemy is None:
        self.last_message = f"未找到敌人配置：{enemy_id}"
        return False
    level = int(self.player["level"])
    enemy_level = max(level, min(enemy["level"], level + 4))
    hp = max(35, min(enemy["hp"], 35 + enemy_level * 18))
    self.combat = {
        "enemy_id": enemy_id,
        "name": enemy["name"],
        "level": enemy_level,
        "hp": hp,
        "max_hp": hp,
        "atk": max(5, min(enemy["atk"], 7 + enemy_level * 3)),
        "def": max(1, min(enemy["def"], 3 + enemy_level * 2)),
        "spd": max(4, min(enemy["spd"], 6 + enemy_level * 2)),
        "exp_reward": max(10, min(enemy["exp_reward"], 12 + enemy_level * 8)),
        "drop_table": enemy["drop_table"],
        "round": 1,
        "defending": False,
        "can_escape": enemy["type"] not in {"boss", "final_boss"},
    }
    self.combat_is_training = False
    self.last_message = f"{enemy['name']}挡住了去路，回合战斗开始。"
    return True

def combat_text(self) -> str:
    if self.combat is None:
        return ""
    return (
        f"第{self.combat['round']}回合｜{self.combat['name']} "
        f"生命 {self.combat['hp']}/{self.combat['max_hp']}\n"
        f"{self.player['name']} 生命 {self.player['hp']}｜斗气 {self.player['douqi']}"
    )

def combat_skills(self) -> List[Dict[str, Any]]:
    return [
        self.skills[skill_id]
        for skill_id in self.player.get("known_skills", [])
        if skill_id in self.skills
    ]

@staticmethod
def _skill_attack_bonus(effect: str) -> int:
    for token in effect.split(","):
        if token.startswith("atk:+"):
            return int(token[5:])
    return 0

def _skill_cost(self, skill: Dict[str, Any]) -> int:
    return max(2, 2 + self._skill_attack_bonus(skill["effect"]) // 15)

def _estimated_attack_damage(self, bonus: int = 0, multiplier: float = 1.0) -> int:
    if self.combat is None:
        return 0
    return max(1, int((self.player["atk"] + bonus) * multiplier) - self.combat["def"])

@staticmethod
def _effect_gain(effect: str, stat: str) -> int:
    prefix = f"{stat}:+"
    for token in effect.split(","):
        if token.startswith(prefix):
            return int(token[len(prefix):])
    return 0

def _combat_healing_items(self) -> List[Tuple[str, int, int]]:
    missing_hp = max(0, int(self.player["max_hp"]) - int(self.player["hp"]))
    missing_douqi = max(
        0,
        int(self.attribute_rules["douqi"]["max"]) - int(self.player["douqi"]),
    )
    candidates = []
    for item_id in self.player.get("items", []):
        item = self.item_rules.get(item_id, {})
        hp_gain = self._effect_gain(item.get("use_effect", ""), "hp")
        douqi_gain = self._effect_gain(item.get("use_effect", ""), "douqi")
        if hp_gain > 0 and missing_hp > 0 and self.check_conditions(item.get("use_condition")):
            effective = min(hp_gain, missing_hp) + min(douqi_gain, missing_douqi)
            candidates.append((item_id, effective, max(0, hp_gain - missing_hp)))
    return sorted(candidates, key=lambda value: (-value[1], value[2]))

def choose_auto_combat_action(self) -> Tuple[str, Optional[str]]:
    if self.combat is None:
        return "none", None

    hp_ratio = self.player["hp"] / max(1, self.player["max_hp"])
    enemy_ratio = self.combat["hp"] / max(1, self.combat["max_hp"])
    enemy_damage = max(1, self.combat["atk"] - self.player["def"])
    healing_items = self._combat_healing_items()

    if healing_items and (hp_ratio <= 0.40 or self.player["hp"] <= enemy_damage * 2):
        return "item", healing_items[0][0]
    if not healing_items and self.player["hp"] <= enemy_damage:
        return "defend", None

    normal_damage = self._estimated_attack_damage()
    if normal_damage >= self.combat["hp"]:
        return "attack", None

    usable_skills = []
    for skill in self.combat_skills():
        bonus = self._skill_attack_bonus(skill["effect"])
        if bonus <= 0:
            continue
        cost = self._skill_cost(skill)
        if self.player["douqi"] < cost:
            continue
        finisher_threshold = FINISHER_SKILLS.get(skill["id"])
        if finisher_threshold is not None and enemy_ratio > finisher_threshold:
            continue
        damage = self._estimated_attack_damage(bonus, 1.25)
        # 保留最后一轮普通攻击所需的斗气余量，避免高消耗技能无意义溢伤。
        score = min(damage, self.combat["hp"]) / cost
        if damage >= self.combat["hp"]:
            score += 100
        if finisher_threshold is not None:
            score += 20
        usable_skills.append((score, skill["id"]))

    if usable_skills:
        return "skill", max(usable_skills)[1]
    if hp_ratio <= 0.30 and self.combat["hp"] > normal_damage * 2:
        return "defend", None
    return "attack", None

def auto_battle(self, max_rounds: int = 200) -> str:
    if self.combat is None:
        self.last_message = "当前没有正在进行的战斗。"
        return "none"
    battle_logs = ["自动战斗开始"]
    result = "continue"
    for _ in range(max_rounds):
        action, target = self.choose_auto_combat_action()
        if action == "none":
            break
        result = self.combat_action(action, target)
        battle_logs.append(self.last_message)
        if result != "continue":
            break
    if result == "continue":
        battle_logs.append("自动战斗达到回合上限，已暂停")
    self.last_message = "；".join(log for log in battle_logs if log)
    return result

def combat_action(self, action: str, skill_id: Optional[str] = None) -> str:
    if self.combat is None:
        return "none"
    combat = self.combat
    logs: List[str] = []
    combat["defending"] = False

    if action == "escape":
        chance = 0.35 + max(0, self.player["spd"] - combat["spd"]) * 0.02
        if combat["can_escape"] and random.random() < min(0.9, chance):
            self.combat = None
            self.advance_time(getattr(self, "combat_time_cost", 0))
            self.last_message = "你抓住空隙脱离了战斗。"
            return "escaped"
        logs.append("你试图撤退，但被对方拦下")
    elif action == "item":
        item_id = skill_id or "item_elixir"
        item = self.item_rules.get(item_id, {})
        hp_gain = self._effect_gain(item.get("use_effect", ""), "hp")
        douqi_gain = self._effect_gain(item.get("use_effect", ""), "douqi")
        if item_id not in self.player["items"] or hp_gain <= 0:
            self.last_message = "背包中没有可用丹药。"
            return "invalid"
        self.player["items"].remove(item_id)
        actual_heal = min(hp_gain, max(0, self.player["max_hp"] - self.player["hp"]))
        actual_douqi = min(
            douqi_gain,
            max(0, self.attribute_rules["douqi"]["max"] - self.player["douqi"]),
        )
        self.player["hp"] += actual_heal
        self.player["douqi"] += actual_douqi
        self._clamp_player_stats()
        logs.append(f"你服下{self.item_name(item_id)}，恢复 {actual_heal} 点生命")
        if actual_douqi:
            logs.append(f"恢复 {actual_douqi} 点斗气")
    elif action == "defend":
        combat["defending"] = True
        logs.append("你凝聚斗气防守")
    else:
        bonus = 0
        multiplier = 1.0
        if action == "skill":
            skill = self.skills.get(skill_id or "")
            if skill is None:
                self.last_message = "尚未掌握该斗技。"
                return "invalid"
            cost = self._skill_cost(skill)
            if self.player["douqi"] < cost:
                self.last_message = "斗气不足，无法施展该斗技。"
                return "invalid"
            self.player["douqi"] -= cost
            bonus = self._skill_attack_bonus(skill["effect"])
            multiplier = 1.25
            logs.append(f"你施展了{skill['name']}")
            finisher_threshold = FINISHER_SKILLS.get(skill["id"])
            enemy_ratio = combat["hp"] / max(1, combat["max_hp"])
            if finisher_threshold is not None and enemy_ratio <= finisher_threshold:
                multiplier *= 2
                logs.append("斗技命中虚弱破绽，触发暴击")
        damage = max(
            1,
            int((self.player["atk"] + bonus) * multiplier)
            - combat["def"]
            + random.randint(-2, 3),
        )
        actual_damage = min(damage, combat["hp"])
        combat["hp"] = max(0, combat["hp"] - actual_damage)
        logs.append(f"对{combat['name']}造成 {actual_damage} 点伤害")

    if combat["hp"] <= 0:
        logs.extend(self._finish_combat_win())
        self.last_message = "；".join(logs)
        return "won"

    enemy_damage = max(
        1,
        combat["atk"] - self.player["def"] + random.randint(-2, 3),
    )
    if combat["defending"]:
        enemy_damage = max(1, enemy_damage // 2)
    self.player["hp"] = max(0, self.player["hp"] - enemy_damage)
    logs.append(f"{combat['name']}反击，造成 {enemy_damage} 点伤害")
    combat["round"] += 1
    if self.player["hp"] <= 0:
        self.player["hp"] = max(1, self.attribute_rules["hp"]["initial"] // 3)
        self.player["stamina"] = 0
        self.player["last_map"] = "map_wutan"
        self.combat = None
        self.advance_time(getattr(self, "combat_time_cost", 0))
        logs.append("你失去意识，被送回乌坦城休养")
        self.last_message = "；".join(logs)
        return "lost"
    self.last_message = "；".join(logs)
    return "continue"

def _finish_combat_win(self) -> List[str]:
    if self.combat is None:
        return []
    combat = self.combat
    logs = [f"你击败了{combat['name']}"]
    logs.extend(self.apply_effects(f"exp:+{combat['exp_reward']},reputation:+1"))
    self.player["adventure_points"] += 2
    if getattr(self, "combat_is_training", False):
        self.player["training_wins"] += 1
    if combat["drop_table"]:
        drops = combat["drop_table"].split("|")
        for drop in drops:
            parts = drop.split(":")
            if len(parts) == 3 and random.randint(1, 100) <= int(parts[2]):
                if parts[0] == "item":
                    item_id = parts[1]
                    if item_id not in self.player["items"]:
                        self.player["items"].append(item_id)
                    logs.append(f"获得{self.item_name(item_id)}")
                elif parts[0] in self.attribute_rules:
                    logs.extend(self.apply_effects(f"{parts[0]}:+{parts[1]}"))
    self.combat = None
    self.advance_time(getattr(self, "combat_time_cost", 0))
    return logs

def story_requirement(self) -> int:
    phase = self.current_story_phase()
    if phase is None:
        return 0
    if self.current_story_subnode() is not None:
        return max(1, int(phase["requirement"]) // 2)
    return int(phase["requirement"])

def _sync_story_phase_id(self) -> None:
    stage = int(self.player.get("story_stage", 0))
    self.player["story_phase_id"] = (
        STORY_PHASES[stage]["id"] if stage < len(STORY_PHASES) else ""
    )

def current_story_phase(self) -> Optional[Dict[str, Any]]:
    stage = int(self.player.get("story_stage", 0))
    return STORY_PHASES[stage] if stage < len(STORY_PHASES) else None

def current_story_subnode(self) -> Optional[Dict[str, Any]]:
    phase = self.current_story_phase()
    if phase is None:
        return None
    substage = int(self.player.get("story_substage", 0))
    return phase["subnodes"][substage] if substage < len(phase["subnodes"]) else None

def advance_story(self) -> bool:
    if not self._can_take_free_action():
        return False
    phase = self.current_story_phase()
    if phase is None:
        self.last_message = "主要目标已经全部完成。"
        return False
    requirement = self.story_requirement()
    if self.player["adventure_points"] < requirement:
        self.last_message = (
            f"还缺少 {requirement - self.player['adventure_points']} 点冒险阅历。"
            "请通过探索、修炼或战斗积累。"
        )
        return False
    subnode = self.current_story_subnode()
    if subnode is not None:
        if not self.check_conditions(subnode.get("condition")):
            self.last_message = (
                f"子节点“{subnode['title']}”尚未达成：{subnode['condition']}。"
                "完成方式可以自由选择。"
            )
            return False
        self.player["adventure_points"] -= requirement
        self.player["story_substage"] += 1
        logs = self.apply_effects(subnode.get("effect"))
        self.last_message = f"子节点完成：{subnode['title']}"
        if logs:
            self.last_message += "；" + "；".join(logs)
        self.advance_time()
        return True
    if not self.check_conditions(phase.get("condition")):
        self.last_message = (
            f"尚未达到“{phase['title']}”的目标条件：{phase['condition']}。"
            "你可以自由探索、修炼和建立关系后再来。"
        )
        return False
    self.player["adventure_points"] -= requirement
    self.player["story_stage"] += 1
    self.player["story_substage"] = 0
    self._sync_story_phase_id()
    logs = self.apply_effects(phase.get("effect"))
    self.last_message = f"关键目标完成：{phase['title']}"
    if logs:
        self.last_message += "；" + "；".join(logs)
    self.advance_time()
    return True

def item_name(self, item_id: str) -> str:
    return self.item_rules.get(item_id, {}).get("name", item_id)

def use_item(self, item_id: str) -> bool:
    if item_id not in self.player["items"]:
        self.last_message = "背包中没有该道具。"
        return False
    item = self.item_rules.get(item_id)
    if item is None or not item.get("use_effect"):
        self.last_message = "该道具当前不能直接使用。"
        return False
    if not self.check_conditions(item.get("use_condition")):
        self.last_message = "尚未满足该道具的使用条件。"
        return False
    self.player["items"].remove(item_id)
    logs = self.apply_effects(item["use_effect"])
    self.last_message = f"使用{item['name']}；" + "；".join(logs)
    return True

def is_ending(self) -> bool:
    return self.current_story_phase() is None

def is_finished(self) -> bool:
    return self.is_ending()

def status_text(self) -> str:
    core_attributes = [
        "level",
        "exp",
        "hp",
        "douqi",
        "atk",
        "def",
        "spd",
        "silver",
        "reputation",
        "alchemy",
        "soul",
    ]
    attribute_text = "｜".join(
        f"{self.attribute_rules[key]['name']} {self.player[key]}"
        for key in core_attributes
        if key in self.attribute_rules
    )
    relationships = []
    for rule in self.relationship_rules.values():
        if not rule.get("visible", False):
            continue
        if rule.get("pre_condition") and not self.check_conditions(
            rule["pre_condition"]
        ):
            continue
        target = rule["target"]
        target_name = self.npc_names.get(target, target)
        relationships.append(
            f"{target_name} {self.relation_value(target)}"
            f"({self.relation_stage(target)})"
        )
    relationship_text = "、".join(relationships) or "无"
    items = "、".join(self.player.get("items", [])) or "无"
    flags = "、".join(self.player.get("flags", [])) or "无"
    node = self.next_schedule_node()
    schedule = (
        f"\n日程：{node['title']}（{self.schedule_countdown_text(node)}）"
        if node
        else ""
    )
    return (
        f"{self.player['name']}｜{self.realm_name()}｜{attribute_text}\n"
        f"{self.time_text()}｜所在区域：{self.current_map()['name']}｜"
        f"冒险阅历 {self.player['adventure_points']}"
        f"｜关键阶段 {self.player['story_stage']}/{len(STORY_PHASES)}"
        f"｜阶段子节点 {self.player['story_substage']}/"
        f"{len(self.current_story_phase()['subnodes']) if self.current_story_phase() else 0}\n"
        f"道具：{items}\n开关：{flags}\n关系：{relationship_text}{schedule}"
    )

