    skill_id = LEVEL_SKILL_MILESTONES.get(level)
    if skill_id and skill_id not in player["known_skills"]:
        player["known_skills"].append(skill_id)
        logs.append(f"领悟斗技：{self.skills[skill_id]['name']}")
    return logs

def breakthrough(self) -> bool:
    """尝试突破到下一等级。返回是否成功。"""
    if self.player["progress"] < 9:
        self.last_message = "修炼进度未满，还无法尝试突破。"
        return False

    level = int(self.player["level"])
    if level >= 99:
        self.last_message = "你已是斗帝之境，无需突破。"
        return False

    if not self._can_take_free_action():
        return False

    chance = self._breakthrough_chance(level)
    success = random.randint(1, 100) <= chance

    boundary_text = "境界" if self._is_realm_boundary(level) else "段内"
    exp_lost = self._exp_for_progress(level) // 2

    if success:
        self.player["level"] = level + 1
        self.player["progress"] = 0
        realm = self.realm_name()
        logs = self._apply_level_gains(level + 1)
        self.last_message = (
            f"{boundary_text}突破成功！你晋升至 {realm} Lv.{level + 1}。"
            f"（成功率 {chance}%）"
        )
        if logs:
            self.last_message += "；" + "；".join(logs)
    else:
        self.player["exp"] = max(0, self.player["exp"] - exp_lost)
        self.last_message = (
            f"{boundary_text}突破失败！（成功率 {chance}%）\n"
            f"你损失了 {exp_lost} 点经验，进度仍为 9/9，可再次尝试。"
        )

    self.advance_time()
    return success

def _apply_progress(
    self, player: Optional[Dict[str, Any]] = None
) -> List[str]:
    """检查 exp 是否足以填充下一个进度点。"""
    player = player if player is not None else self.player
    logs: List[str] = []
    while True:
        if int(player.get("progress", 0)) >= 9:
            break  # 需要突破，不能自动升级
        level = int(player.get("level", 1))
        exp_needed = self._exp_for_progress(level)
        if int(player.get("exp", 0)) < exp_needed:
            break
        player["exp"] = int(player["exp"]) - exp_needed
        player["progress"] = int(player.get("progress", 0)) + 1
        logs.append(f"修炼进度提升至 {player['progress']}/9")
        if int(player["progress"]) >= 9:
            logs.append("修炼进度已满！可以尝试突破。")
            break
    return logs

