import re
import unicodedata
from typing import Optional

from wordworld.core.engine import GameEngine
from wordworld.config.paths import SAVE_PATH


_CHINESE_NUMBER_MAP = {
    "零": 0,
    "〇": 0,
    "一": 1,
    "二": 2,
    "两": 2,
    "三": 3,
    "四": 4,
    "五": 5,
    "六": 6,
    "七": 7,
    "八": 8,
    "九": 9,
}

_MAIN_COMMAND_ALIASES = {
    "探索": "1",
    "探索区域": "1",
    "移动": "2",
    "移动区域": "2",
    "区域移动": "2",
